import{supabase}from './supabase-client.js';export const auth={async signUp(email,password,metadata={}){const{data,error}=await supabase.auth.signUp({email,password,options:{data: metadata}});return{data,error};},async signIn(email,password){const{data,error}=await supabase.auth.signInWithPassword({email,password});return{data,error};},async signInWithOAuth(provider){const{data,error}=await supabase.auth.signInWithOAuth({provider,options:{redirectTo: `${window.location.origin}/portal/dashboard.html`}});return{data,error};},async signOut(){const{error}=await supabase.auth.signOut();if(!error)window.location.href='/portal/login.html';return{error};},async getUser(){const{data:{user}}=await supabase.auth.getUser();return user;},async getSession(){const{data:{session}}=await supabase.auth.getSession();return session;},async isAuthenticated(){const session=await this.getSession();return!!session;},async updateProfile(updates){const{data,error}=await supabase.auth.updateUser(updates);return{data,error};},async resetPassword(email){const{data,error}=await supabase.auth.resetPasswordForEmail(email,{redirectTo: `${window.location.origin}/portal/reset-password.html`});return{data,error};},async resendConfirmation(email){const{data,error}=await supabase.auth.resend({type: 'signup',email});return{data,error};}};export class AuthManager{constructor(){this.currentUser=null;this.listeners=new Set();this.init();}init(){supabase.auth.onAuthStateChange((event,session)=>{this.currentUser=session?.user||null;this.notifyListeners(event,session);});this.getSession();}async getSession(){const{data:{session}}=await supabase.auth.getSession();this.currentUser=session?.user||null;return session;}subscribe(callback){this.listeners.add(callback);return()=>this.listeners.delete(callback);}notifyListeners(event,session){this.listeners.forEach(callback=>callback(event,session));}isAuthenticated(){return!!this.currentUser;}getUser(){return this.currentUser;}}export const authGuards={async requireAuth(redirectUrl='/portal/login.html'){const session=await auth.getSession();if(!session){window.location.href=redirectUrl;return false;}return true;},async redirectIfAuth(redirectUrl='/portal/dashboard.html'){const session=await auth.getSession();if(session){window.location.href=redirectUrl;return true;}return false;},async requireRole(requiredRole){const user=await auth.getUser();if(!user)return false;const{data: profile}=await supabase .from('user_profiles').select('role').eq('user_id',user.id).single();return profile?.role===requiredRole;},async requireAnyRole(roles){const user=await auth.getUser();if(!user)return false;const{data: profile}=await supabase .from('user_profiles').select('role').eq('user_id',user.id).single();return roles.includes(profile?.role);}};export default auth;